import React, { useState, useEffect } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { coursesAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import Spinner from "../components/Spinner";

const CourseDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);
  const [enrolling, setEnrolling] = useState(false);
  const [enrolled, setEnrolled] = useState(false);
  const [error, setError] = useState("");
  const [activeTab, setActiveTab] = useState("overview");

  useEffect(() => {
    const fetch = async () => {
      setLoading(true);
      try {
        const { data } = await coursesAPI.getById(id);
        setCourse(data);
      } catch { setError("Course not found."); }
      finally { setLoading(false); }
    };
    fetch();
  }, [id]);

  const handleEnroll = async () => {
    if (!isAuthenticated) { navigate("/login"); return; }
    setEnrolling(true);
    try {
      await coursesAPI.enroll(id);
      setEnrolled(true);
    } catch (err) {
      const msg = err.response?.data?.message || "";
      if (msg.includes("Already enrolled")) setEnrolled(true);
      else setError(msg || "Enrollment failed.");
    } finally { setEnrolling(false); }
  };

  if (loading) return <Spinner message="Loading course..." />;
  if (error && !course) return <div className="page-error">{error}</div>;
  if (!course) return null;

  const tabClass = (tab) => `nav-link fw-semibold ${activeTab === tab ? "active" : ""}`;
  const tabStyle = (tab) => ({
    color: activeTab === tab ? "#6c63ff" : "#9999bb",
    borderBottom: activeTab === tab ? "2px solid #6c63ff" : "2px solid transparent",
    background: "none", borderTop: "none", borderLeft: "none", borderRight: "none",
    padding: "12px 20px", cursor: "pointer"
  });

  return (
    <div style={{ paddingBottom: 80 }}>
      {/* Hero Banner */}
      <div style={{ background: "linear-gradient(135deg, #16213e 0%, #1a1a2e 100%)", borderBottom: "1px solid #2a2a4a", padding: "48px 0" }}>
        <div className="container">
          <div className="row g-4 align-items-start">
            {/* Left: Course info */}
            <div className="col-12 col-lg-8">
              <nav aria-label="breadcrumb" className="mb-3">
                <ol className="breadcrumb mb-0" style={{ background: "none", padding: 0 }}>
                  <li className="breadcrumb-item"><Link to="/" style={{ color: "#6c63ff" }}>Courses</Link></li>
                  <li className="breadcrumb-item active" style={{ color: "#666688" }}>{course.category}</li>
                </ol>
              </nav>

              <span className="badge mb-3 px-3 py-2" style={{ background: "rgba(108,99,255,0.15)", color: "#6c63ff", border: "1px solid rgba(108,99,255,0.3)", borderRadius: 50, fontWeight: 600 }}>
                {course.category}
              </span>

              <h1 className="fw-bold mb-3" style={{ color: "#e8e8f0", fontSize: "clamp(1.5rem,4vw,2.2rem)", lineHeight: 1.3 }}>
                {course.title}
              </h1>

              <p className="mb-4" style={{ color: "#9999bb", lineHeight: 1.7, maxWidth: 600 }}>{course.description}</p>

              {/* Meta badges */}
              <div className="d-flex flex-wrap gap-3 mb-3">
                {[
                  { icon: "bi-person-fill", val: course.instructor },
                  { icon: "bi-clock", val: course.duration },
                  { icon: "bi-collection-play", val: `${course.lessons?.length} lessons` },
                  { icon: "bi-bar-chart", val: course.level },
                  { icon: "bi-people-fill", val: `${course.enrolledCount?.toLocaleString()} students` }
                ].map((m, i) => (
                  <span key={i} className="small d-flex align-items-center gap-1" style={{ color: "#9999bb" }}>
                    <i className={`bi ${m.icon}`} style={{ color: "#6c63ff" }}></i> {m.val}
                  </span>
                ))}
              </div>

              <div className="d-flex align-items-center gap-2">
                <span style={{ color: "#ffbb57", fontSize: "1.1rem" }}>{"★".repeat(Math.floor(course.rating || 4.5))}</span>
                <span className="fw-bold" style={{ color: "#e8e8f0" }}>{(course.rating || 4.5).toFixed(1)}</span>
              </div>
            </div>

            {/* Right: Enroll card */}
            <div className="col-12 col-lg-4">
              <div className="card border-0 shadow-lg" style={{ background: "#0f0f1a", border: "1px solid #2a2a4a !important", borderRadius: 14 }}>
                <img
                  src={course.thumbnail || "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=400"}
                  alt={course.title}
                  className="card-img-top"
                  style={{ height: 180, objectFit: "cover", borderRadius: "14px 14px 0 0" }}
                  onError={e => { e.target.src = "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=400"; }}
                />
                <div className="card-body p-4">
                  <div className="fw-bold mb-3" style={{ fontSize: "1.6rem", color: "#43d9ad" }}>Free</div>

                  {enrolled ? (
                    <button className="btn w-100 fw-bold mb-3" onClick={() => navigate(`/player/${id}`)}
                      style={{ background: "#43d9ad", color: "#0f0f1a", border: "none", borderRadius: 10, padding: "13px" }}>
                      <i className="bi bi-play-circle me-2"></i>Start Learning
                    </button>
                  ) : (
                    <button className="btn w-100 fw-bold mb-3" onClick={handleEnroll} disabled={enrolling}
                      style={{ background: "#6c63ff", color: "white", border: "none", borderRadius: 10, padding: "13px" }}>
                      {enrolling ? <><span className="spinner-border spinner-border-sm me-2"></span>Enrolling...</> : "Enroll Now — It's Free"}
                    </button>
                  )}

                  {error && <div className="alert alert-danger py-2 small">{error}</div>}

                  <ul className="list-unstyled mb-0 d-flex flex-column gap-2">
                    {["Full lifetime access", `${course.lessons?.length} structured lessons`, "Progress tracking", "Certificate on completion"].map((f, i) => (
                      <li key={i} className="small" style={{ color: "#9999bb" }}>
                        <i className="bi bi-check-circle-fill me-2" style={{ color: "#43d9ad" }}></i>{f}
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="container mt-4">
        <div className="d-flex border-bottom mb-4" style={{ borderColor: "#2a2a4a" }}>
          {["overview", "lessons", "instructor"].map(tab => (
            <button key={tab} style={tabStyle(tab)} onClick={() => setActiveTab(tab)}>
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>

        {activeTab === "overview" && (
          <div>
            <h5 className="fw-bold mb-3" style={{ color: "#e8e8f0" }}>What You'll Learn</h5>
            <div className="row g-3 mb-4">
              {course.lessons?.slice(0, 6).map((l, i) => (
                <div key={i} className="col-12 col-md-6">
                  <div className="d-flex align-items-start gap-2 p-3 rounded-3" style={{ background: "#1a1a2e", border: "1px solid #2a2a4a" }}>
                    <i className="bi bi-check2-circle mt-1" style={{ color: "#43d9ad" }}></i>
                    <span className="small" style={{ color: "#9999bb" }}>{l.title}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "lessons" && (
          <div>
            <h5 className="fw-bold mb-3" style={{ color: "#e8e8f0" }}>Course Content — {course.lessons?.length} Lessons</h5>
            <div className="d-flex flex-column gap-2">
              {course.lessons?.map((l, i) => (
                <div key={i} className="d-flex align-items-center gap-3 p-3 rounded-3" style={{ background: "#1a1a2e", border: "1px solid #2a2a4a" }}>
                  <div className="d-flex align-items-center justify-content-center rounded-circle fw-bold small"
                    style={{ width: 30, height: 30, background: "#2a2a4a", color: "#9999bb", flexShrink: 0 }}>
                    {i + 1}
                  </div>
                  <span className="flex-grow-1 small fw-semibold" style={{ color: "#e8e8f0" }}>{l.title}</span>
                  <span className="small" style={{ color: "#666688" }}><i className="bi bi-clock me-1"></i>{l.duration}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "instructor" && (
          <div className="p-4 rounded-3" style={{ background: "#1a1a2e", border: "1px solid #2a2a4a" }}>
            <div className="d-flex gap-4 align-items-start">
              <div className="d-flex align-items-center justify-content-center rounded-circle fw-bold fs-3"
                style={{ width: 72, height: 72, background: "linear-gradient(135deg,#6c63ff,#ff6584)", color: "white", flexShrink: 0 }}>
                {course.instructor?.charAt(0).toUpperCase()}
              </div>
              <div>
                <h5 className="fw-bold mb-1" style={{ color: "#e8e8f0" }}>{course.instructor}</h5>
                <p className="small mb-2" style={{ color: "#6c63ff" }}>Senior Software Engineer & Educator</p>
                <p className="small mb-3" style={{ color: "#9999bb", lineHeight: 1.7 }}>
                  An experienced developer and passionate educator with years of industry experience in {course.category}. Known for clear explanations and practical, real-world examples.
                </p>
                <div className="d-flex gap-3 flex-wrap">
                  {[`⭐ ${(course.rating||4.5).toFixed(1)} Rating`, `👥 ${course.enrolledCount?.toLocaleString()} Students`, "📚 1 Course"].map((s,i)=>(
                    <span key={i} className="small" style={{ color: "#666688" }}>{s}</span>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CourseDetails;
